class Solution:
    def maxNonOverlapping(self, nums, target: int) -> int:
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        dp = [0] * (n + 1)
        for i in range(1, n + 1):
            dp[i] = dp[i - 1]
            for j in range(i):
                if prefix[i] - prefix[j] == target:
                    dp[i] = max(dp[i], dp[j] + 1)
        return dp[n]

