var maxNonOverlapping = function(nums, target) {
    let seen = new Set([0]);
    let prefix = 0;
    let count = 0;
    for (const x of nums) {
        prefix += x;
        if (seen.has(prefix - target)) {
            count++;
            seen = new Set([0]);
            prefix = 0;
        } else {
            seen.add(prefix);
        }
    }
    return count;
};
